import {
  forwardRef,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import O9Button from '../Button/Button';
import O9IconButton from '../IconButton/IconButton';
import { useControllableState } from '../../hooks/useControllableState';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ButtonGroupItem {
  value: string;
  label?: string;
  icon?: string;
  isDisabled?: boolean;
  isExcluded?: boolean;
}

export interface ButtonGroupChangeDetail {
  value: string | string[] | null;
  previousValue: string | string[] | null;
  changedValue?: string;
  isSelected?: boolean;
}

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

export interface O9ButtonGroupProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange' | 'defaultValue'> {
  items: ButtonGroupItem[];
  value?: string | string[] | null;
  defaultValue?: string | string[] | null;
  variant?: 'primary' | 'secondary';
  size?: 'sm' | 'lg';
  isMultiSelect?: boolean;
  isIconOnly?: boolean;
  hasOverflow?: boolean;
  expandOnSelect?: boolean;
  isDisabled?: boolean;
  isLoading?: boolean;
  ariaLabel: string;
  onChange?: (detail: ButtonGroupChangeDetail) => void;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9ButtonGroup = forwardRef<HTMLDivElement, O9ButtonGroupProps>(
  function O9ButtonGroup(
    {
      items,
      value: valueProp,
      defaultValue = null,
      variant = 'primary',
      size = 'lg',
      isMultiSelect = false,
      isIconOnly = false,
      hasOverflow = false,
      expandOnSelect = false,
      isDisabled = false,
      isLoading = false,
      ariaLabel,
      onChange,
      className,
      ...rest
    },
    ref
  ) {
    const [value, setValue] = useControllableState(valueProp, defaultValue);

    const containerRef = useRef<HTMLDivElement>(null);
    const itemRefs = useRef<(HTMLButtonElement | null)[]>([]);
    const overflowTriggerRef = useRef<HTMLButtonElement>(null);
    const overflowMenuRef = useRef<HTMLDivElement>(null);
    const [hiddenIndices, setHiddenIndices] = useState<Set<number>>(new Set());
    const [overflowOpen, setOverflowOpen] = useState(false);

    const effectiveExpandOnSelect = expandOnSelect && !isMultiSelect;

    const buttonSize = size === 'sm' ? 'sm' : 'md';

    // ── Class computation ──────────────────────────────────────────────
    const classes = useMemo(() =>
      [
        'o9ds-btn-grp',
        `o9ds-btn-grp--${variant}`,
        `o9ds-btn-grp--${size}`,
        isMultiSelect && 'o9ds-btn-grp--multi',
        isIconOnly && 'o9ds-btn-grp--icon-only',
        hasOverflow && 'o9ds-btn-grp--overflow',
        effectiveExpandOnSelect && 'o9ds-btn-grp--expand-lbl',
        isDisabled && 'is-disabled',
        isLoading && 'loading',
        className,
      ].filter(Boolean).join(' '),
      [variant, size, isMultiSelect, isIconOnly, hasOverflow, effectiveExpandOnSelect, isDisabled, isLoading, className]
    );

    // ── Selection logic ────────────────────────────────────────────────
    const isItemActive = useCallback(
      (itemValue: string): boolean => {
        if (isMultiSelect) {
          return Array.isArray(value) && value.includes(itemValue);
        }
        return value === itemValue;
      },
      [value, isMultiSelect]
    );

    const handleItemClick = useCallback(
      (itemValue: string) => {
        if (isDisabled || isLoading) return;

        const item = items.find(i => i.value === itemValue);
        if (!item || item.isDisabled) return;

        if (isMultiSelect) {
          const currentValues = (Array.isArray(value) ? value : []) as string[];
          const idx = currentValues.indexOf(itemValue);
          const isSelected = idx === -1;
          const newValues = isSelected
            ? [...currentValues, itemValue]
            : currentValues.filter(v => v !== itemValue);

          setValue(newValues);
          onChange?.({
            value: newValues,
            previousValue: [...currentValues],
            changedValue: itemValue,
            isSelected: isSelected,
          });
        } else {
          if (value === itemValue) return;
          setValue(itemValue);
          onChange?.({
            value: itemValue,
            previousValue: (value as string | null) ?? null,
          });
        }
      },
      [isDisabled, isLoading, items, isMultiSelect, value, onChange, setValue]
    );

    // ── Roving tabindex ────────────────────────────────────────────────
    const getRovingTabIndex = useCallback(
      (index: number, itemValue: string): number => {
        if (hiddenIndices.has(index)) return -1;

        const enabledVisibleItems = items
          .map((item, i) => ({ item, i }))
          .filter(({ item, i }) => !item.isDisabled && !isDisabled && !hiddenIndices.has(i));

        if (enabledVisibleItems.length === 0) return -1;

        const selectedItem = enabledVisibleItems.find(({ item }) => isItemActive(item.value));
        if (selectedItem) {
          return selectedItem.item.value === itemValue ? 0 : -1;
        }

        return enabledVisibleItems[0]?.i === index ? 0 : -1;
      },
      [items, isDisabled, hiddenIndices, isItemActive]
    );

    // ── Keyboard navigation ───────────────────────────────────────────
    const handleKeyDown = useCallback(
      (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (isDisabled || isLoading) return;

        const { key } = event;
        const isArrow = key === 'ArrowLeft' || key === 'ArrowRight';
        const isEdge = key === 'Home' || key === 'End';
        const isActivate = key === 'Enter' || key === ' ';

        if (!isArrow && !isEdge && !isActivate) return;

        const enabledItems = items
          .map((item, i) => ({ item, i, el: itemRefs.current[i] }))
          .filter(({ item, i, el }) => el && !item.isDisabled && !isDisabled && !hiddenIndices.has(i));

        if (enabledItems.length === 0) return;

        const focusedEl = document.activeElement;
        const currentEnabledIdx = enabledItems.findIndex(({ el }) => el === focusedEl);

        if (isArrow || isEdge) {
          event.preventDefault();

          let targetIdx: number;
          if (key === 'ArrowRight') {
            targetIdx = currentEnabledIdx === -1 ? 0 : (currentEnabledIdx + 1) % enabledItems.length;
          } else if (key === 'ArrowLeft') {
            targetIdx = currentEnabledIdx === -1 ? enabledItems.length - 1 : (currentEnabledIdx - 1 + enabledItems.length) % enabledItems.length;
          } else if (key === 'Home') {
            targetIdx = 0;
          } else {
            targetIdx = enabledItems.length - 1;
          }

          const targetItem = enabledItems[targetIdx];
          if (targetItem?.el) {
            for (const el of itemRefs.current) {
              if (el) el.tabIndex = -1;
            }
            targetItem.el.tabIndex = 0;
            targetItem.el.focus();

            if (!isMultiSelect) {
              handleItemClick(targetItem.item.value);
            }
          }
        } else if (isActivate) {
          event.preventDefault();
          if (currentEnabledIdx !== -1) {
            handleItemClick(enabledItems[currentEnabledIdx].item.value);
          }
        }
      },
      [isDisabled, isLoading, items, hiddenIndices, isMultiSelect, handleItemClick]
    );

    // ── Overflow detection ─────────────────────────────────────────────
    useEffect(() => {
      if (!hasOverflow) return;
      const container = containerRef.current;
      if (!container) return;

      const checkOverflow = () => {
        const containerRect = container.getBoundingClientRect();
        const triggerWidth = overflowTriggerRef.current?.offsetWidth ?? 0;
        const availableWidth = containerRect.width - triggerWidth;
        const newHidden = new Set<number>();

        for (let i = 0; i < itemRefs.current.length; i++) {
          const el = itemRefs.current[i];
          if (!el) continue;
          el.style.visibility = '';
          el.style.position = '';
          el.style.pointerEvents = '';
        }

        for (let i = 0; i < itemRefs.current.length; i++) {
          const el = itemRefs.current[i];
          if (!el) continue;
          const btnRect = el.getBoundingClientRect();
          if (btnRect.right > containerRect.left + availableWidth) {
            newHidden.add(i);
            el.style.visibility = 'hidden';
            el.style.position = 'absolute';
            el.style.pointerEvents = 'none';
          }
        }

        setHiddenIndices(prev => {
          if (prev.size === newHidden.size && [...prev].every(v => newHidden.has(v))) return prev;
          return newHidden;
        });
      };

      const observer = new ResizeObserver(checkOverflow);
      observer.observe(container);
      checkOverflow();

      return () => observer.disconnect();
    }, [hasOverflow, items]);

    // ── Close overflow on outside click ────────────────────────────────
    useEffect(() => {
      if (!overflowOpen) return;

      const handleDocClick = (e: MouseEvent) => {
        if (overflowMenuRef.current?.contains(e.target as Node)) return;
        if (overflowTriggerRef.current?.contains(e.target as Node)) return;
        setOverflowOpen(false);
      };

      document.addEventListener('click', handleDocClick);
      return () => document.removeEventListener('click', handleDocClick);
    }, [overflowOpen]);

    // ── Render ──────────────────────────────────────────────────────────
    const mergedRef = useCallback(
      (node: HTMLDivElement | null) => {
        (containerRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
        if (typeof ref === 'function') ref(node);
        else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
      },
      [ref]
    );

    return (
      <div
        ref={mergedRef}
        className={classes}
        role="toolbar"
        aria-orientation="horizontal"
        aria-label={ariaLabel}
        aria-busy={isLoading || undefined}
        onKeyDown={handleKeyDown}
        {...rest}
      >
        {items.map((item, index) => {
          const isActive = isItemActive(item.value);
          const isItemDisabled = isDisabled || (item.isDisabled ?? false);
          const isItemLoading = isLoading && !(item.isExcluded ?? false);
          const useAsIconOnly = isIconOnly || (effectiveExpandOnSelect && !isActive && !!item.icon);
          const tabIdx = getRovingTabIndex(index, item.value);

          const refCallback = (el: HTMLButtonElement | null) => {
            itemRefs.current[index] = el;
          };

          const handleClick = () => handleItemClick(item.value);

          if (useAsIconOnly || (!item.label && item.icon)) {
            return (
              <O9IconButton
                key={item.value}
                ref={refCallback}
                icon={item.icon ?? ''}
                tooltip={item.label ?? item.value}
                variant="tertiary"
                size={buttonSize}
                isDisabled={isItemDisabled}
                isLoading={isItemLoading}
                isSelected={isActive}
                tabIndex={tabIdx}
                data-value={item.value}
                onClick={handleClick}
              />
            );
          }

          return (
            <O9Button
              key={item.value}
              ref={refCallback}
              label={item.label ?? item.value}
              icon={item.icon}
              variant="tertiary"
              size={buttonSize}
              isDisabled={isItemDisabled}
              isLoading={isItemLoading}
              isSelected={isActive}
              tabIndex={tabIdx}
              data-value={item.value}
              onClick={handleClick}
            />
          );
        })}

        {hasOverflow && hiddenIndices.size > 0 && (
          <O9IconButton
            ref={overflowTriggerRef}
            className="o9ds-btn-grp__overflow"
            icon="ellipsis-v"
            tooltip="More actions"
            variant="tertiary"
            size={buttonSize}
            isDisabled={isDisabled}
            aria-haspopup="menu"
            aria-expanded={overflowOpen}
            onClick={() => setOverflowOpen(o => !o)}
          />
        )}

        {overflowOpen && hiddenIndices.size > 0 && (
          <div
            ref={overflowMenuRef}
            className="o9ds-btn-grp__overflow-menu"
            role="menu"
          >
            {[...hiddenIndices].map(idx => {
              const item = items[idx];
              if (!item) return null;
              const active = isItemActive(item.value);
              return (
                <O9Button
                  key={item.value}
                  role="menuitem"
                  label={item.label ?? item.value}
                  icon={item.icon}
                  variant="tertiary"
                  size={buttonSize}
                  isDisabled={item.isDisabled}
                  isSelected={active}
                  data-value={item.value}
                  onClick={() => {
                    handleItemClick(item.value);
                    setOverflowOpen(false);
                  }}
                />
              );
            })}
          </div>
        )}
      </div>
    );
  }
);

export default O9ButtonGroup;
